	getFirstHalf(features: any[]) {
		if (!features || !Array.isArray(features)) return [];
		return features.slice(0, Math.ceil(features.length / 2));
	}

	getSecondHalf(features: any[]) {
		if (!features || !Array.isArray(features)) return [];
		return features.slice(Math.ceil(features.length / 2));
	}

