	getRate() {
		this.payementservice.getExchangeRate().subscribe((res: any) => {
			if (res.result === "success") {
				this.exchangeRate = res.conversion_rates.USD;
				console.log('Exchange rate updated:', this.exchangeRate);
			}
		});
	}
	convertPrice(price: number | null | undefined) {

		if (!price) return '';

		let value = price;

		if (this.currency === 'USD') {
			value = Math.round(price * this.exchangeRate);
		}

		return value.toLocaleString();
	}
	getStandoutCount() {

		if (!this.selectedPackage) return 1;

		const plan = this.selectedPackage.plan?.toLowerCase();

		if (plan === 'shopify') {
			return 2;
		}

		if (plan === 'magento') {
			return 6;
		}
		if (plan === 'custom commerce') {
			return 0;
		}

		return 1;
	}

	getEcommercePackages() {
		let obj = {
			category: 'Ecommerce',
		};
		this.payementservice.getFilterPackages(obj).subscribe((res: any) => {
			if (res.body.code === 200) {
				const packages = res.body.result;
				const featured = this.packageData.find((pkg) => pkg.isFeatured);
				const others = this.packageData.filter((pkg) => !pkg.isFeatured);
				if (featured) {
					this.packageData = [others[0], featured, others[1]];
				} else {
					this.packageData = packages.sort((a, b) => a.price - b.price);
				}
				this.selectedPackage = featured || this.packageData[1];
			}
		});
	}
