	submitPayment() {
		this.isPaymentSubmitted = true;
		if (this.paymentForm.invalid) {
			return;
		}
		if (this.paymentData) {
			this.paymentData['email'] = this.paymentForm.value.email;
			this.paymentData['customer_name'] = this.paymentForm.value.name;
			this.paymentData['base_url'] = environment.baseUrl;
			this.paymentData['firstname'] = this.paymentForm.value.firstname;
			this.paymentData['lastname'] = this.paymentForm.value.lastname;
			this.paymentData['contact'] =
				this.paymentForm.value.contact.internationalNumber;
			this.paymentData['company'] = this.paymentForm.value.company;
			this.paymentData['company_address'] =
				this.paymentForm.value.company_address;
			this.paymentData['message'] = this.paymentForm.value.customer_message;
			this.paymentData['type'] = 'Ecommerce';
			this.paymentData['website'] = this.paymentForm.value.website;
			this.payementservice
				.stripePayments(this.paymentData)
				.subscribe((response) => {
					if (response.body.code == 200) {
						// window.location.href = response.body.url;
						this.isPaymentSubmitted = false;
						localStorage.setItem(
							'stripe-payment-user',
							JSON.stringify(this.paymentData)
						);
						this.paymentForm.reset();
						// window.open(response.body.url, '_blank');
						this.modalService.dismissAll();
						this.showAlert({
							icon: 'success',
							html: "<h1>Thank you</h1> <br> <h6>For submitting you request!<h6> <br> <p> We're thrilled to assist you with your Ecommerce Website Service Journey!</p> <br><p> One of our team members will contact you shortly to discuss requirements!</p>",
							showConfirmButton: true,
							confirmButtonText: 'Sure! Looking forward',
							customClass: {
								confirmButton: 'success-button',
							},
						});
					} else if (response.body.code == 400) {
					} else {
					}
				});
		}
	}

	closePopUp() {
		this.modalService.dismissAll();
	}

	ngAfterViewInit() {
		if (!this.isBrowser || !this.videoElement?.nativeElement?.play) {
			return;
		}

		const elem = this.videoElement.nativeElement;
		elem.muted = true; // Ensure the video is muted for autoplay compatibility
		elem.loop = true; // Ensure the video is muted for autoplay compatibility

		// Attempt to autoplay the video when the component initializes
		elem.play().catch((err) => {
			console.log('Autoplay failed, user interaction may be required:', err);
		});

		this.lazyLoader.loadScript('https://unpkg.com/@splinetool/viewer/build/spline-viewer.js')
			.then(() => console.log('Spline viewer loaded'))
			.catch(() => console.error('Failed to load spline viewer script'));
	}


	playInFullscreenWithAudio() {
		if (!this.isBrowser || !this.videoElement?.nativeElement?.play) {
			return;
		}

		const elem = this.videoElement.nativeElement;

		// Unmute the video
		elem.muted = false;

		// Remove controls to avoid interference in fullscreen mode
		elem.removeAttribute('controls');

		// Attempt to play the video and request fullscreen
		elem
			.play()
			.then(() => {
				if (elem.requestFullscreen) {
					elem.requestFullscreen();
				} else if (elem.webkitRequestFullscreen) {
					// Safari
					elem.webkitRequestFullscreen();
				} else if (elem.msRequestFullscreen) {
					// IE11
					elem.msRequestFullscreen();
				} else if (elem.mozRequestFullScreen) {
					// Firefox
					elem.mozRequestFullScreen();
				}
			})
			.catch((err) => {
				console.log('Error entering fullscreen with audio: ', err);
			});
	}

	@HostListener('document:fullscreenchange', ['$event'])
	onFullscreenChange() {
		if (!this.isBrowser || !this.videoElement?.nativeElement) {
			return;
		}

		const elem = this.videoElement.nativeElement;

		if (
			this.document.fullscreenElement === elem ||
			(this.document as any).webkitFullscreenElement === elem ||
			(this.document as any).msFullscreenElement === elem ||
			(this.document as any).mozFullScreenElement === elem
		) {
			// Video is in fullscreen, attempt to play
			elem.play().catch((err) => {
				console.log('Could not play in fullscreen mode:', err);
			});
		} else {
			// Video exited fullscreen, restore controls and mute the video
			elem.setAttribute('controls', '');
			elem.muted = true;
		}
	}

	openModal() {
		const modalElement = document.getElementById('contactModal');
		this.renderer.addClass(modalElement, 'show');
		this.renderer.setStyle(modalElement, 'display', 'block');
		this.renderer.setStyle(modalElement, 'backgroundColor', 'rgba(0,0,0,0.5)');
		document.body.classList.add('modal-open');
	}

	closeModal() {
		const modalElement = document.getElementById('contactModal');
		this.renderer.removeClass(modalElement, 'show');
		this.renderer.setStyle(modalElement, 'display', 'none');
		document.body.classList.remove('modal-open');
	}

	submitReferral() {
		this.submitted = true;
		if (!this.referralForm.valid) {
			return;
		}
		this.isSubmitting = true;
		this.isLoading = true; // Show loading indicator
		if (
			this.referralForm.value.referrer_email ==
			this.referralForm.value.referred_email
		) {
			this.isEmailSame = true;
			this.isLoading = false;
			return;
		}
		if (
			this.referralForm.value.referrer_phone.internationalNumber ==
			this.referralForm.value.referred_phone.internationalNumber
		) {
			this.isContactSame = true;
			this.isLoading = false;
			return;
		}
		if (this.referralForm.valid) {
			this.referralForm.value['referrer_phone'] =
				this.referralForm.value.referrer_phone.internationalNumber;
			this.referralForm.value['referred_phone'] =
				this.referralForm.value.referred_phone.internationalNumber;
			this.referralService.addReferral(this.referralForm.value).subscribe(
				(response) => {
					if (response.body.code == 200) {
						// console.log('Email sent successfully', response);
						this.successMessage =
							'Thank you for referring your friend! We’ve sent an invitation to your friend and will notify you once they join us. Stay tuned for your rewards!';
						this.errorMessage = '';
						this.isSubmitting = false;
						this.isLoading = false; // Hide loading indicator
						this.referralForm.reset();
						this.submitted = false;
						this.closeModal();
						this.showAlert({
							icon: 'success',
							html: '<h1>Thank you</h1> <br> <h6>For referring your friend!!<h6> <br> <p> We’ve sent an invitation to your friend</p> <br><p>We will notify you once they join us. Stay tuned for your rewards!</p>',
							showConfirmButton: true,
							confirmButtonText: 'Sure! Looking forward',
							customClass: {
								confirmButton: 'success-button',
							},
						});
					} else if (response.body.code == 400) {
						this.errorMessage = response.body.message;
						this.isSubmitting = false;
						this.isLoading = false; // Hide loading indicator
						// Auto-hide success message after 3 seconds
						setTimeout(() => {
							this.errorMessage = '';
							this.submitted = false;
						}, 5000);
					}
				},
				(error) => {
					console.error('Error sending email', error);
					this.errorMessage =
						'Failed to send your message. Please try again later.';
					this.isSubmitting = false;
					this.isLoading = false; // Hide loading indicator

					// Auto-hide error message after 3 seconds
					setTimeout(() => {
						this.errorMessage = '';
					}, 5000);
				}
			);
		} else {
			this.errorMessage = 'Please fill in all required fields.';
			this.isSubmitting = false;
			this.isLoading = false; // Hide loading indicator

			setTimeout(() => {
				this.errorMessage = '';
			}, 3000);
		}
	}
